#!/usr/bin/env bash
set -eu
# 如果支持 pipefail 就打开（dash 不支持会跳过）
(set -o pipefail) 2>/dev/null && set -o pipefail
set -x
timestamp=$(date "+%Y%m%d_%H%M%S")
workspace_id="wso1gao759kjyz4p"   # rjob 不使用，但保留注释方便对照
enable_preemptible_job=False       # rjob 不使用
aimaster_enable=False              # rjob 不使用
dlc_config_path=/cpfs01/shared/public/chenyongkang/launch_worker/config  # rjob 不使用
model_path=/mnt/shared-storage-user/songdemin/user/hezhishu/xpuyu_sft/work/go-sft-0912-checkpoint-5000-500step/20251203002109/hf-2500
chat_template=qwen2
data_path=/mnt/shared-storage-user/llmbr-share/hezhishu/H-transfer/Go-Reward-models/Annotation_data/original/sft_data
hf_interval=40
checkpoint_interval=40
epochs=5
data_desc=medcal-r1-rollout
data_type=jsonl
work_dir="/mnt/shared-storage-user/songdemin/user/hezhishu/xpuyu_sft/work"
cache_dir="/mnt/shared-storage-user/songdemin/user/hezhishu/xpuyu_sft/cache_data_$data_desc"
worker_count=1
worker_gpu=4
global_batch_size=16
exp_name="1203_RFT_hf-2500-14k-5epoch-50step"
rjob_image="registry.h.pjlab.org.cn/ailab-puyullmgpu/xpuyu:0.3.0-torch-2.6.0-0513"
script_path="/mnt/shared-storage-user/songdemin/user/hezhishu/xpuyu_sft/run_xpuyu_sft_${timestamp}.sh"
mkdir -p "$(dirname "$script_path")"
cat > "$script_path" <<"EOF_RUN"
#!/usr/bin/env bash
set -e
set -u
(set -o pipefail) 2>/dev/null && set -o pipefail
set -x
model_path=${model_path:?model_path not set}
data_path=${data_path:-}
work_dir=${work_dir:?work_dir not set}
exp_name=${exp_name:-"exp"}
cache_dir=${cache_dir:?cache_dir not set}
chat_template=${chat_template:-"qwen2"}
global_batch_size=${global_batch_size:-64}
data_type=${data_type:-"jsonl"}
epochs=${epochs:-1}
hf_interval=${hf_interval:-100}
checkpoint_interval=${checkpoint_interval:--1}
export TORCH_DISTRIBUTED_TIMEOUT=${TORCH_DISTRIBUTED_TIMEOUT:-3600000}
export NCCL_IB_TC=${NCCL_IB_TC:-136}
export NCCL_IB_SL=${NCCL_IB_SL:-5}
export NCCL_IB_GID_INDEX=${NCCL_IB_GID_INDEX:-3}
export NCCL_SOCKET_IFNAME=${NCCL_SOCKET_IFNAME:-bond1}
export NCCL_DEBUG=${NCCL_DEBUG:-INFO}
export NCCL_IB_HCA=${NCCL_IB_HCA:-mlx5_bond}
export NCCL_IB_TIMEOUT=${NCCL_IB_TIMEOUT:-22}
export NCCL_IB_QPS_PER_CONNECTION=${NCCL_IB_QPS_PER_CONNECTION:-8}
export NCCL_MIN_NCHANNELS=${NCCL_MIN_NCHANNELS:-4}
export PYTORCH_CUDA_ALLOC_CONF=${PYTORCH_CUDA_ALLOC_CONF:-'expandable_segments:True'}
NPROC_PER_NODE=${NPROC_PER_NODE:-8}
: "${MASTER_ADDR:?MASTER_ADDR not set}"
: "${NODE_COUNT:?NODE_COUNT not set}"
: "${NODE_RANK:?NODE_RANK not set}"
MASTER_PORT=${MASTER_PORT:-6000}
torchrun \
  --nproc-per-node="${NPROC_PER_NODE}" \
  --master_addr="${MASTER_ADDR}" \
  --master_port="${MASTER_PORT}" \
  --nnodes="${NODE_COUNT}" \
  --node_rank="${NODE_RANK}" \
  -m xpuyu.tools.sft \
    --llm "${model_path}" \
    --dset-cache-dir "${cache_dir}" \
    --dset-pack-level expand_soft --use-fa3 --max-length 32768 \
    --dset-file-types ".${data_type}" \
    --dataset "${data_path}" --file-pattern ".*\.${data_type}" \
    --global-batch-size "${global_batch_size}" \
    --chat-template "${chat_template}" \
    --lr 0.00004 --lr-min 0.000004 --wd 0.1 \
    --sp-size 1 --group-by-length --selective-recompute 1.0 --compile \
    --feishu-webhook "https://open.feishu.cn/open-apis/bot/v2/hook/a4be899c-44fa-434a-ab9f-12a9754492d9" \
    --work-dir "${work_dir}/${exp_name}/" \
    --checkpoint-interval "${checkpoint_interval}" \
    --hf-interval "${hf_interval}" \
    --dset-formats processed --global-pack --seed 42 \
    --epochs "${epochs}" \
    --enable-fp8 \
    --checkpoint-max-keep 999
EOF_RUN
chmod +x "$script_path"
rjob submit -e DISTRIBUTED_JOB=true \
  --image="${rjob_image}" \
  --host-network=true \
  --name "${exp_name}" \
  -P "${worker_count}" \
  --gpu "${worker_gpu}" \
  --cpu 32 \
  --memory 1048576 \
  --charged-group llmbr_gpu \
  --private-machine='group' \
  --gang-start=true \
  --mount=gpfs://gpfs1/songdemin:/mnt/shared-storage-user/songdemin \
  --mount=gpfs://gpfs1/large-model-center-share-weights:/mnt/shared-storage-user/large-model-center-share-weights \
  --mount=gpfs://gpfs1/llmbr-share:/mnt/shared-storage-user/llmbr-share \
  --custom-resources rdma/mlnx_shared=8 \
  --custom-resources mellanox.com/mlnx_rdma=1 \
  -- bash -ecx "
    # 将外层变量注入到 runner 进程环境
    export model_path='${model_path}';
    export data_path='${data_path}';
    export work_dir='${work_dir}';
    export exp_name='${exp_name}';
    export cache_dir='${cache_dir}';
    export chat_template='${chat_template}';
    export global_batch_size='${global_batch_size}';
    export data_type='${data_type}';
    export epochs='${epochs}';
    export hf_interval='${hf_interval}';
    export checkpoint_interval='${checkpoint_interval}';
    export NPROC_PER_NODE='${worker_gpu}';
    bash '${script_path}'
  "
echo "rjob 已提交：${exp_name}"
echo "runner 脚本：${script_path}"
